using System.ComponentModel;
using System.Net;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- In-memory notebook used by the note-taking tool ---
List<string> notebook = [];

// --- Tool definitions -------------------------------------------------------

[Description("Search the web for a query and return a list of result snippets. Use this to gather information on a research topic.")]
string WebSearch([Description("The search query")] string query)
{
    using HttpClient http = new();
    // Use DuckDuckGo Instant Answer API (no key required)
    var encoded = WebUtility.UrlEncode(query);
    var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

    var json = http.GetStringAsync(url).GetAwaiter().GetResult();
    using var doc = JsonDocument.Parse(json);
    var root = doc.RootElement;

    List<string> results = [];

    // Abstract text (top-level answer)
    if (root.TryGetProperty("AbstractText", out var abs) && abs.GetString() is { Length: > 0 } abstractText)
        results.Add($"[Abstract] {abstractText}");

    // Related topics
    if (root.TryGetProperty("RelatedTopics", out var topics))
    {
        foreach (var topic in topics.EnumerateArray().Take(5))
        {
            if (topic.TryGetProperty("Text", out var text) && text.GetString() is { Length: > 0 } t)
                results.Add($"[Related] {t}");
        }
    }

    return results.Count > 0
        ? string.Join("\n\n", results)
        : "No results found. Try rephrasing the query or breaking it into sub-queries.";
}

[Description("Save a research note. Use this to record key facts, findings, or quotes you discover during research.")]
string SaveNote(
    [Description("Short label for the note")] string title,
    [Description("The content of the note")] string content)
{
    notebook.Add($"## {title}\n{content}");
    return $"Note saved ({notebook.Count} total).";
}

[Description("Retrieve all saved research notes so far.")]
string GetNotes()
{
    return notebook.Count == 0
        ? "No notes saved yet."
        : string.Join("\n\n---\n\n", notebook);
}

// --- Build the AI chat client & tools ---------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient();

var tools = new[]
{
    AIFunctionFactory.Create(WebSearch),
    AIFunctionFactory.Create(SaveNote),
    AIFunctionFactory.Create(GetNotes),
};

var chatOptions = new ChatOptions { Tools = [.. tools] };

// --- Agent loop -------------------------------------------------------------

Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.Write("> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();

    List<ChatMessage> messages =
    [
        new(ChatRole.System, """
            You are a research agent. Given a topic, you MUST:
            1. Search the web multiple times with varied queries to gather broad information.
            2. Save important findings as notes using the SaveNote tool.
            3. After gathering enough information (at least 3 searches), retrieve your notes
               and produce a well-structured summary with sections and key takeaways.
            Always search before answering. Never fabricate facts.
            """),
        new(ChatRole.User, $"Research the following topic and provide a comprehensive summary:\n\n{topic}")
    ];

    Console.WriteLine($"\nResearching \"{topic}\"...\n");

    // Agentic tool-call loop
    const int maxIterations = 15;
    for (int i = 0; i < maxIterations; i++)
    {
        var response = await chatClient.GetResponseAsync(messages, chatOptions);

        // Append all response messages to history
        messages.AddRange(response.Messages);

        // Check if any message contains tool calls that need processing
        bool hasToolCalls = false;
        foreach (var msg in response.Messages)
        {
            if (msg.Contents.OfType<FunctionCallContent>().Any())
            {
                hasToolCalls = true;
                foreach (var call in msg.Contents.OfType<FunctionCallContent>())
                {
                    Console.WriteLine($"  🔧 {call.Name}({TruncateArgs(call.Arguments)})");
                    var result = await call.InvokeAsync(tools);
                    messages.Add(new ChatMessage(ChatRole.Tool,
                        [new FunctionResultContent(call.CallId, result)]));
                }
            }
        }

        if (!hasToolCalls)
        {
            // Final text response — print and break
            var text = string.Join("", response.Messages
                .SelectMany(m => m.Contents)
                .OfType<TextContent>()
                .Select(t => t.Text));
            Console.WriteLine($"\n{"─"}\n{text}\n");
            break;
        }
    }
}

Console.WriteLine("Goodbye!");

static string TruncateArgs(IDictionary<string, object?>? args)
{
    if (args is null || args.Count == 0) return "";
    var s = string.Join(", ", args.Select(kv => $"{kv.Key}: {kv.Value}"));
    return s.Length > 80 ? s[..80] + "…" : s;
}

